const text = (($json.text || '') + '').toLowerCase().trim();

let route = 'llm';

// 1. Calendar
if (/календар|зустріч|план|розклад/i.test(text)) {
  route = 'calendar';
}
// 2. Expense
else if (/витрати|витратив|кошт|грн|czk|usd|eur|грош|купив|ціна|заплатив|робоч|годин/i.test(text)) {
  route = 'expense';
}
// 3. Task
else if (/задач|список|справ|нагадай|нотат|запис/i.test(text)) {
  route = 'task';
}
// 4. Search
else if (/знайди|пошук|інтернет|гугл|google/i.test(text)) {
  route = 'search';
}
// 5. Chat
else if (/привіт|добрий|hello|hi|дякую|\/start/i.test(text)) {
  route = 'chat';
}

return { route, text };

const items = input;
const chats = new Set(items.map(item => item.json.telegram_chat_id).filter(Boolean));
return Array.from(chats).map(chatId => ({ json: { telegram_chat_id: chatId } }));

const cb = $('Telegram Trigger').item.json.callback_query;
if (!cb) return [];
const data = cb.data.split(':'); // e.g. "done:uuid"
return [{
  json: {
    callback_id: cb.id,
    message_id: cb.message.message_id,
    chat_id: cb.message.chat.id,
    action: data[0],
    event_id: data[1],
    original_text: cb.message.text
  }
}];

const tasks = $input.all()[0].json;
if (!tasks || tasks.length === 0) {
  return [{ json: { text: "🎉 У вас немає відкритих задач!", inline_keyboard: [] } }];
}

let text = "📋 <b>Ваші активні задачі:</b>\n\n";
const keyboard = [];

tasks.forEach((task, index) => {
  const num = index + 1;
  text += `${num}. ${task.title}\n`;
  keyboard.push([
    { text: `✅ Виконати (${num})`, callback_data: `done:${task.id}` },
    { text: `⏰ Завтра`, callback_data: `tom:${task.id}` }
  ]);
});

return [{ json: { text: text, inline_keyboard: keyboard } }];
